import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

export const Schema = z.object({
  主角: z.object({
    位阶: z.coerce.number().transform(v => _.clamp(v, 1, 9)).prefault(1),
    掌控度: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
    附身状态: z.boolean().prefault(false),
    战后性欲: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
    能力列表: z.array(z.string()).prefault(["色孽感官", "灵异直觉"]),
    驾驭的鬼: z.array(z.object({
      姓名: z.string(),
      类型: z.string(),
      能力: z.string(),
      简介: z.string(),
      实力: z.string()
    })).prefault([]),
    物品栏: z.array(z.string()).prefault([])
  }).superRefine((data, ctx) => {
    // 限制驾驭鬼的数量不得超过位阶
    if (data.驾驭的鬼.length > data.位阶) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: `驾驭的鬼数量 (${data.驾驭的鬼.length}) 不得超过位阶等级 (${data.位阶})`,
        path: ["驾驭的鬼"]
      });
    }

    // 根据位阶限制掌控度上限
    let maxAuthority = 0;
    if (data.位阶 === 3) {
      maxAuthority = 10;
    } else if (data.位阶 > 3) {
      // 位阶 4-9 解锁上限，简单设定为 (位阶-2)*15 + 10，9阶达成试炼前上限 100
      maxAuthority = Math.min(100, (data.位阶 - 3) * 15 + 10);
    }

    if (data.掌控度 > maxAuthority) {
      ctx.addIssue({
        code: z.ZodIssueCode.custom,
        message: `当前位阶 (Tier ${data.位阶}) 的掌控度上限为 ${maxAuthority}%，当前值为 ${data.掌控度}%`,
        path: ["掌控度"]
      });
    }
  }),
  世界: z.object({
    时间: z.string().prefault("2026年1月30日 下午 14:00"),
    地点: z.string().prefault("大江市·某待拆迁公寓"),
    当前灵异事件: z.string().prefault("凶宅逃生"),
    危险等级: z.string().prefault("C")
  })
});

$(() => {
  registerMvuSchema(Schema);
})

